async function handleWaitForCode(client2, args) {
  const timeoutMs = (args.timeout_seconds ?? 120) * 1e3;
  const pollIntervalMs = 5e3;
  const startTime = Date.now();
  let order;
  try {
    order = await client2.createOrder(args.service, args.country);
  } catch (err) {
    throw new Error(`Failed to buy number: ${err.message}`);
  }
  const orderId = order.order_id;
  const phoneNumber = order.phone_number;
  const apiKey = client2.getApiKey();
  const baseUrl = client2.getBaseUrl();
  if (apiKey) {
    const remainingMs = timeoutMs - (Date.now() - startTime);
    const wsResult = await waitForSMSViaWebSocket(baseUrl, apiKey, orderId, remainingMs);
    if (wsResult) {
      return {
        content: [
          {
            type: "text",
            text: JSON.stringify(
              {
                success: true,
                phone_number: phoneNumber,
                sms_code: wsResult.sms_code,
                sms_text: wsResult.sms_text,
                order_id: orderId,
                delivery_method: wsResult.delivery_method,
                elapsed_seconds: Math.round((Date.now() - startTime) / 1e3)
              },
              null,
              2
            )
          }
        ]
      };
    }
  }
  let attempts = 0;
  while (Date.now() - startTime < timeoutMs) {
    attempts++;
    try {
      const status = await client2.getOrder(orderId);
      if (status.sms_code) {
        return {
          content: [
            {
              type: "text",
              text: JSON.stringify(
                {
                  success: true,
                  phone_number: phoneNumber,
                  sms_code: status.sms_code,
                  sms_text: status.sms_text,
                  order_id: orderId,
                  delivery_method: "polling",
                  elapsed_seconds: Math.round((Date.now() - startTime) / 1e3),
                  poll_attempts: attempts
                },
                null,
                2
              )
            }
          ]
        };
      }
      if (status.status === "cancelled" || status.status === "failed") {
        throw new Error(
          `Order ${orderId} was ${status.status} before SMS arrived.`
        );
      }
    } catch (err) {
      const message = err.message;
      if (!message.includes("waiting") && !message.includes("pending")) {
        throw err;
      }
    }
    const remaining = timeoutMs - (Date.now() - startTime);
    if (remaining <= 0) break;
    await sleep(Math.min(pollIntervalMs, remaining));
  }
  return {
    content: [
      {
        type: "text",
        text: JSON.stringify(
          {
            success: false,
            error: "timeout",
            message: `No SMS received within ${args.timeout_seconds} seconds.`,
            order_id: orderId,
            phone_number: phoneNumber,
            tip: "Use check_sms with this order_id to check if code arrived later, or cancel_order to get a refund."
          },
          null,
          2
        )
      }
    ]
  };
}
function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}
async function handleFindCheapest(client2, args) {
  const limit = args.limit ?? 5;
  const countries = await client2.listCountries();
  const results = [];
  const batchSize = 10;
  for (let i = 0; i < countries.length; i += batchSize) {
    const batch = countries.slice(i, i + batchSize);
    const priceChecks = await Promise.allSettled(
      batch.map(async (c) => {
        const price = await client2.checkPrice(args.service, c.iso);
        return {
          country: c.iso,
          country_name: c.name,
          price_usd: price.price_usd,
          stock: price.available
        };
      })
    );
    for (const result of priceChecks) {
      if (result.status === "fulfilled" && result.value.stock) {
        results.push(result.value);
      }
    }
  }
  results.sort((a, b) => a.price_usd - b.price_usd);
  const top = results.slice(0, limit);
  if (top.length === 0) {
    return {
      content: [
        {
          type: "text",
          text: JSON.stringify(
            {
              service: args.service,
              cheapest_options: [],
              total_available_countries: 0,
              message: `No countries available for service "${args.service}". Use search_service to verify the service code, or list_services to see all available services.`
            },
            null,
            2
          )
        }
      ]
    };
  }
  return {
    content: [
      {
        type: "text",
        text: JSON.stringify(
          {
            service: args.service,
            cheapest_options: top,
            total_available_countries: results.length
          },
          null,
          2
        )
      }
    ]
  };
}
async function handleSearchService(client2, args) {
  const services = await client2.listServices();
  const query = args.query.toLowerCase().trim();
  const scored = services.map((s) => {
    const name = s.name.toLowerCase();
    const code = s.code.toLowerCase();
    let score = 0;
    if (code === query || name === query) {
      score = 1;
    } else if (code.startsWith(query) || name.startsWith(query)) {
      score = 0.9;
    } else if (code.includes(query) || name.includes(query)) {
      score = 0.7;
    } else {
      const queryTokens = query.split(/\s+/);
      const nameTokens = name.split(/[\s_-]+/);
      let matches2 = 0;
      for (const qt of queryTokens) {
        if (nameTokens.some((nt) => nt.includes(qt) || qt.includes(nt))) {
          matches2++;
        }
      }
      if (matches2 > 0) {
        score = matches2 / Math.max(queryTokens.length, nameTokens.length) * 0.6;
      }
    }
    return { code: s.code, name: s.name, match_score: Math.round(score * 100) / 100 };
  });
  const matches = scored.filter((s) => s.match_score >= 0.5).sort((a, b) => b.match_score - a.match_score).slice(0, 5);
  return {
    content: [
      {
        type: "text",
        text: JSON.stringify(
          matches.length > 0 ? {
            query: args.query,
            matches,
            tip: `Use the "code" field as the service parameter in other tools.`
          } : {
            query: args.query,
            matches: [],
            message: "No matching services found",
            tip: `Try list_services to browse all available services.`
          },
          null,
          2
        )
      }
    ]
  };
}
async function handleActiveOrders(client2, args) {
  const orders = await client2.listOrders(args.status);
  return {
    content: [
      {
        type: "text",
        text: JSON.stringify(
          {
            count: orders.length,
            orders: orders.map((o) => ({
              order_id: o.order_id,
              phone_number: o.phone_number,
              status: o.status,
              sms_code: o.sms_code,
              sms_text: o.sms_text,
              expires_at: o.expires_at
            })),
            tip: orders.length > 0 ? "Use check_sms with any order_id to get the latest status, or cancel_order to refund pending orders." : "No orders found."
          },
          null,
          2
        )
      }
    ]
  };
}

